object AppLogger {
    private const val MAX_LOG_CHUNK = 4000
    private const val DEFAULT_TAG = "AppLogger"

    fun init(context: Context, enableVerboseLogging: Boolean = true) {
        Timber.uprootAll()
        if (enableVerboseLogging) {
            Timber.plant(VerboseTree())
        } else {
            Timber.plant(ReleaseTree())
        }
    }

    fun v(tag: String = DEFAULT_TAG, message: String) = logLong(Log.VERBOSE, tag, message)
    fun d(tag: String = DEFAULT_TAG, message: String) = logLong(Log.DEBUG, tag, message)
    fun i(tag: String = DEFAULT_TAG, message: String) = logLong(Log.INFO, tag, message)
    fun w(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        if (throwable != null) {
            logLong(Log.WARN, tag, "$message\n${Log.getStackTraceString(throwable)}")
        } else {
            logLong(Log.WARN, tag, message)
        }
    }

    fun e(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        if (throwable != null) {
            logLong(Log.ERROR, tag, "$message\n${Log.getStackTraceString(throwable)}")
        } else {
            logLong(Log.ERROR, tag, message)
        }
    }

    fun authAttempt(
        username: String?,
        userId: String? = null,
        method: String,
        success: Boolean,
        failureReason: String? = null,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        val result = if (success) "SUCCESS" else "FAILED"
        val meta = metadata.entries.joinToString(", ") { "${it.key}=${it.value}" }
        val msg = buildString {
            append("AUTH_ATTEMPT result=").append(result)
            append(", method=").append(method)
            append(", username=").append(username)
            append(", userId=").append(userId)
            if (!failureReason.isNullOrBlank()) append(", failureReason=").append(failureReason)
            if (meta.isNotBlank()) append(", metadata={").append(meta).append("}")
        }
        if (success) i("Auth", msg) else w("Auth", msg)
    }

    fun databaseQuery(
        sql: String,
        parameters: List<Any?> = emptyList(),
        durationMs: Long? = null,
        rowsAffected: Int? = null,
        throwable: Throwable? = null
    ) {
        val msg = buildString {
            append("DB_QUERY sql=").append(sql)
            append(", params=").append(parameters.joinToString(prefix = "[", postfix = "]"))
            if (durationMs != null) append(", durationMs=").append(durationMs)
            if (rowsAffected != null) append(", rowsAffected=").append(rowsAffected)
        }
        if (throwable != null) {
            e("Database", msg, throwable)
        } else {
