        }
    }

    fun apiRequest(
        method: String,
        url: String,
        headers: Map<String, String>,
        requestBody: String?,
        responseCode: Int? = null,
        responseHeaders: Map<String, String>? = null,
        responseBody: String? = null,
        durationMs: Long? = null,
        throwable: Throwable? = null
    ) {
        val msg = buildString {
            append("API_REQUEST method=").append(method)
            append(", url=").append(url)
            append("\nrequestHeaders=").append(headers.entries.joinToString(prefix = "{", postfix = "}") { "${it.key}=${it.value}" })
            append("\nrequestBody=").append(requestBody ?: "null")
            if (responseCode != null) append("\nresponseCode=").append(responseCode)
            if (responseHeaders != null) {
                append("\nresponseHeaders=").append(responseHeaders.entries.joinToString(prefix = "{", postfix = "}") { "${it.key}=${it.value}" })
            }
            if (responseBody != null) append("\nresponseBody=").append(responseBody)
            if (durationMs != null) append("\ndurationMs=").append(durationMs)
        }
        if (throwable != null) {
            e("Api", msg, throwable)
        } else {
            v("Api", msg)
        }
    }

    fun exception(tag: String = "Exception", throwable: Throwable, message: String? = null) {
        val finalMessage = if (message.isNullOrBlank()) {
            "Unhandled exception"
        } else {
            message
        }
        e(tag, finalMessage, throwable)
    }

    private fun logLong(priority: Int, tag: String, message: String) {
        if (message.length <= MAX_LOG_CHUNK) {
            Timber.tag(tag).log(priority, message)
            return
        }

        var i = 0
        while (i < message.length) {
            val end = (i + MAX_LOG_CHUNK).coerceAtMost(message.length)
            Timber.tag(tag).log(priority, message.substring(i, end))
            i = end
        }
    }

    private class VerboseTree : Timber.DebugTree() {
        override fun createStackElementTag(element: StackTraceElement): String {
            return "APP:${super.createStackElementTag(element) ?: DEFAULT_TAG}"
        }

        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            when (priority) {
                Log.VERBOSE -> if (t != null) Log.v(tag, message, t) else Log.v(tag, message)
                Log.DEBUG -> if (t != null) Log.d(tag, message, t) else Log.d(tag, message)
                Log.INFO -> if (t != null) Log.i(tag, message, t) else Log.i(tag, message)
                Log.WARN -> if (t != null) Log.w(tag, message, t) else Log.w(tag, message)
                Log.ERROR, Log.ASSERT -> if (t != null) Log.e(tag, message, t) else Log.e(tag, message)
                else -> if (t != null) Log.println(priority, tag, "$message\n${Log.getStackTraceString(t)}") else Log.println(priority, tag, message)
            }
        }
    }

    private class ReleaseTree : Timber.Tree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            if (priority >= Log.INFO) {
                if (t != null) {
                    Log.println(priority, tag ?: DEFAULT_TAG, "$message\n${Log.getStackTraceString(t)}")
                } else {
                    Log.println(priority, tag ?: DEFAULT_TAG, message)
                }
            }
        }
    }
