class LoggingInterceptor(
    private val redactHeaders: Set<String> = emptySet()
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val requestStartNs = System.nanoTime()

        val requestHeaders = linkedMapOf<String, String>()
        for (name in request.headers.names()) {
            requestHeaders[name] = if (redactHeaders.contains(name.lowercase()) || redactHeaders.contains(name)) {
                "██REDACTED██"
            } else {
                request.header(name).orEmpty()
            }
        }

        val requestBodyString = request.body?.let { bodyToString(it) }

        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - requestStartNs)

            val responseHeaders = linkedMapOf<String, String>()
            for (name in response.headers.names()) {
                responseHeaders[name] = if (redactHeaders.contains(name.lowercase()) || redactHeaders.contains(name)) {
                    "██REDACTED██"
                } else {
                    response.header(name).orEmpty()
                }
            }

            val responseBodyString = response.peekBody(Long.MAX_VALUE).string()

            AppLogger.apiRequest(
                method = request.method,
                url = request.url.toString(),
                headers = requestHeaders,
                requestBody = requestBodyString,
                responseCode = response.code,
                responseHeaders = responseHeaders,
                responseBody = responseBodyString,
                durationMs = tookMs
            )

            response
        } catch (t: Throwable) {
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - requestStartNs)
            AppLogger.apiRequest(
                method = request.method,
                url = request.url.toString(),
                headers = requestHeaders,
                requestBody = requestBodyString,
                durationMs = tookMs,
                throwable = t
            )
            throw t
        }
    }

    private fun bodyToString(requestBody: RequestBody): String {
        return try {
            val buffer = Buffer()
            requestBody.writeTo(buffer)
            val charset = requestBody.contentType()?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            buffer.readString(charset)
        } catch (e: Exception) {
            "Unable to read request body: ${e.message}"
        }
    }
}

