object ExceptionLogging {
    fun log(throwable: Throwable, message: String? = null, tag: String = "Exception") {
        AppLogger.exception(tag = tag, throwable = throwable, message = message)
    }

    fun setAsDefaultUncaughtExceptionHandler() {
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            AppLogger.e(
                tag = "Fatal",
                message = "Uncaught exception on thread=${thread.name}",
                throwable = throwable
            )
            defaultHandler?.uncaughtException(thread, throwable)
        }
    }
}

